sys_script_include.script:
var DynamicDropdownAPI = Class.create();
DynamicDropdownAPI.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {


    getParentValues: function() {
        console.log("getParentValues called");
        var countries = [];
        var added = {};

        var gr = new GlideRecord('x_1954494_dynami_0_dropdown_mapping');
        gr.query();

        while (gr.next()) {

            //var country = gr.parent_value.toString();
            var country = gr.getValue('parent_value');
            gs.info(country);
            if (!added[country]) {
                countries.push(country);
                added[country] = true;
            }
        }

        return JSON.stringify(countries);
        //return JSON.stringify(["India", "USA", "Canada"]);

    },

    getChildValues: function() {

        var parentValue = this.getParameter('sysparm_parent_value');

        var states = [];

        var gr = new GlideRecord('x_1954494_dynami_0_dropdown_mapping');
        gr.addQuery('parent_value', parentValue);
        gr.query();

        while (gr.next()) {
            states.push(gr.child_value.toString());
        }

        return JSON.stringify(states);
    },

    type: 'DynamicDropdownAPI'
});
